-- ==================== 模拟测试用户数据 ====================
-- 运行前请确认已在正确的数据库中
-- USE hospital_registration_system;

-- 批量插入测试用户（密码统一为 123456）

-- 查看插入结果
SELECT id, real_name AS 姓名, phone AS 手机号,
       DATE_FORMAT(create_time, '%Y-%m-%d %H:%i') AS 注册时间,
       CASE WHEN last_login_time IS NULL THEN '从未登录'
            ELSE DATE_FORMAT(last_login_time, '%Y-%m-%d %H:%i') END AS 最后登录,
       CASE WHEN status = 0 THEN '正常' ELSE '禁用' END AS 状态
FROM user
ORDER BY id;
